import{exibirAlerta}from"./alertaadicao.js";import{indicarProdutosNoCarrinhoEFavoritos}from"./indicador-notificacao.js";function ouvinteBotaoFavoritar(){new botaoFavoritar}class botaoFavoritar{constructor(){this.botoesFavoritos=document.querySelectorAll(".botao-favoritos i"),this.favoritos=JSON.parse(localStorage.getItem("meusFavoritos"))||[],this.buscarFavoritosClientes(),this.ouvinteBotaoFavoritar()}ouvinteBotaoFavoritar(){this.botoesFavoritos.forEach(i=>{i.addEventListener("click",async()=>{let t=i.closest(".card").dataset.id;var o=JSON.parse(localStorage.getItem("idUser"));if(this.favoritos.includes(t)){try{var r=await fetch("https://ecomerce-echomoda.onrender.com/api/remover-favoritos",{method:"DELETE",headers:{"Content-Type":"application/json"},body:JSON.stringify({idclient:o,idproduto:Number(t)})});200===r.status&&exibirAlerta("Produto removido dos favoritos","sucesso"),400===r.status&&exibirAlerta("Erro ao remover produto","erro")}catch(o){exibirAlerta("Tivemos um erro com o servidor","erro")}this.favoritos=this.favoritos.filter(o=>o!==t),i.style.color="inherit"}else{this.favoritos.push(t),i.style.color="gold";try{if(200!==(await fetch("https://ecomerce-echomoda.onrender.com/api/salvar-favoritos",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({idclient:o,idproduto:Number(t)})})).status)return void exibirAlerta("Produto ja esta nos favoritos","erro");exibirAlerta("Produto adicionado aos favoritos","sucesso")}catch(o){return void exibirAlerta("Erro com o servidor",o)}localStorage.setItem("meusFavoritos",JSON.stringify(this.favoritos))}localStorage.setItem("meusFavoritos",JSON.stringify(this.favoritos)),indicarProdutosNoCarrinhoEFavoritos()})})}async buscarFavoritosClientes(){if(0===this.favoritos.length){var o=JSON.parse(localStorage.getItem("idUser"));try{var t=await fetch("https://ecomerce-echomoda.onrender.com/api/buscar-favoritos?idclient="+o,{method:"GET",headers:{"Content-Type":"application/json"}}),r=await t.json();if(200!==t.status)return;var i=r.map(o=>o.id_produto);localStorage.setItem("meusFavoritos",JSON.stringify(i)),this.favoritos=i}catch(o){exibirAlerta("Erro com o servidor",o)}indicarProdutosNoCarrinhoEFavoritos()}}}export{ouvinteBotaoFavoritar};